import{c,$ as l,Q as i,j as h,m as o,h as r,ax as t,n,o as d,S as s}from"./chunks/framework.CWuRYD45.js";const m="/_pr/289/assets/2026-05-01-googleworkspace-cli-cover.CpnCiJkk.webp",k=JSON.parse('{"title":"When the Rubric Forgot What It Found: The googleworkspace/cli Scoring Drift Study","description":"","frontmatter":{},"headers":[],"relativePath":"case-studies/2026-05-01-googleworkspace-cli.md","filePath":"case-studies/2026-05-01-googleworkspace-cli.md","lastUpdated":null}'),u={name:"case-studies/2026-05-01-googleworkspace-cli.md"};function p(g,e,f,b,w,y){const a=l("Mermaid");return i(),h("div",null,[e[2]||(e[2]=o('<h1 id="when-the-rubric-forgot-what-it-found-the-googleworkspace-cli-scoring-drift-study" tabindex="-1">When the Rubric Forgot What It Found: The googleworkspace/cli Scoring Drift Study <a class="header-anchor" href="#when-the-rubric-forgot-what-it-found-the-googleworkspace-cli-scoring-drift-study" aria-label="Permalink to &quot;When the Rubric Forgot What It Found: The googleworkspace/cli Scoring Drift Study&quot;">​</a></h1><p><img src="'+m+'" alt="Cover"></p><blockquote><p><strong>Disclosure</strong>: This article was generated by an automated pipeline using Claude (Sonnet 4.6) based on audit data and GitHub records. It describes work performed by NLPM tooling maintained by <a href="https://github.com/xiaolai" target="_blank" rel="noreferrer">xiaolai</a>. Readers should weigh claims accordingly.</p></blockquote><hr><h2 id="the-project" tabindex="-1">The Project <a class="header-anchor" href="#the-project" aria-label="Permalink to &quot;The Project&quot;">​</a></h2><p><a href="https://github.com/googleworkspace" target="_blank" rel="noreferrer">Google Workspace</a> maintains <a href="https://github.com/googleworkspace/cli" target="_blank" rel="noreferrer">googleworkspace/cli</a>: a single command-line tool that wraps Drive, Gmail, Calendar, Sheets, Docs, Chat, Admin, and more. The API surface is generated dynamically from Google&#39;s Discovery Service. The repository also ships a set of AI agent skills — SKILL.md files that teach Claude Code how to compose Workspace API calls into useful workflows. At time of audit, the project had <strong>25,597 stars</strong> and 1,315 forks.</p><p>The AI skill library is what attracted the NLPM audit. Ninety-six SKILL.md files, spanning API skills, helper skills, persona definitions, recipes, and workflow compositions, represent one of the largest structured skill collections publicly available for Claude Code. Auditing it felt like reviewing the citations in a small encyclopedia — most were airtight; a few pointed nowhere.</p><hr><h2 id="the-audit" tabindex="-1">The Audit <a class="header-anchor" href="#the-audit" aria-label="Permalink to &quot;The Audit&quot;">​</a></h2><p><strong>Date</strong>: 2026-04-06 | <strong>Artifacts scanned</strong>: 96 | <strong>Strategy</strong>: progressive <strong>NL Score</strong>: 99/100 | <strong>Security</strong>: REVIEW</p><p>The score of 99 reflects an unusually clean library — the kind where a penalty stands out like a scuff on a freshly polished floor. Eighty-four of 96 artifacts scored a perfect 100. Only 12 files drew any penalty at all, and none fell below 88.</p>',11)),(i(),r(s,null,{default:t(()=>[d(a,{id:"mermaid-31",class:"mermaid-diagram",graph:"pie%20title%20Score%20Distribution%20%E2%80%94%20Original%20Audit%20(96%20artifacts)%0A%20%20%20%20%22100%2F100%22%20%3A%2084%0A%20%20%20%20%2295%E2%80%9398%22%20%3A%2010%0A%20%20%20%20%2288%22%20%3A%202%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=o('<p>The ten artifacts in the 95–98 range fell into three distinct failure modes: missing concrete CLI commands in recipe steps (five files), a single <code>--document-id</code> vs <code>--document</code> flag inconsistency replicated across four files, and a missing <code>## API Resources</code> section in <code>gws-modelarmor</code> (one file). The two files at 88 contained actual functional bugs.</p><h3 id="top-issues" tabindex="-1">Top Issues <a class="header-anchor" href="#top-issues" aria-label="Permalink to &quot;Top Issues&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>File</th><th>Score</th><th>Issue</th></tr></thead><tbody><tr><td>1</td><td><code>skills/recipe-post-mortem-setup/SKILL.md</code></td><td>88</td><td>Step 1 calls <code>gws docs +write --title ... --body ...</code> — neither flag exists; required flags <code>--document</code> and <code>--text</code> are absent. Command will fail at runtime with a CLI error. <em>(High confidence, documentation analysis — not live-tested.)</em></td></tr><tr><td>2</td><td><code>skills/recipe-collect-form-responses/SKILL.md</code></td><td>88</td><td>Step 1 calls <code>gws forms forms list</code> — the Google Forms API v1 has no <code>list</code> method on the forms resource. <em>(High confidence, documentation analysis — not live-tested.)</em></td></tr><tr><td>3</td><td><code>skills/gws-modelarmor/SKILL.md</code></td><td>95</td><td>No <code>## API Resources</code> section, the one structural element present on every other gws-* API skill.</td></tr><tr><td>4–7</td><td>Four recipe files</td><td>95</td><td>Steps describing &quot;review the output,&quot; &quot;compare the data,&quot; or &quot;for each row&quot; with no corresponding CLI command.</td></tr><tr><td>8–10</td><td>Three recipe files</td><td>98</td><td><code>--document-id</code> used where <code>gws-docs-write</code> documents <code>--document</code>.</td></tr></tbody></table><p>The security scan found no critical patterns. One HIGH finding — an unvalidated <code>$1</code> argument in <code>scripts/show-art.sh</code> — was classified as a false positive (dev-only ASCII art utility with no automated call surface). A MEDIUM finding flagged <code>cargo install cargo-llvm-cov</code> without a hash pin in <code>scripts/coverage.sh</code>. A LOW finding noted <code>^</code> semver pinning in <code>package.json</code> devDependencies.</p><p>The audit recommended submitting PRs for the two recipe bugs and filing a GitHub issue for the MEDIUM security finding.</p><hr><h2 id="what-was-submitted" tabindex="-1">What Was Submitted <a class="header-anchor" href="#what-was-submitted" aria-label="Permalink to &quot;What Was Submitted&quot;">​</a></h2><p>The contribute step opened one tracking issue and four pull requests at the target repository.</p><p><strong>Issue #761</strong> — <a href="https://github.com/googleworkspace/cli/issues/761" target="_blank" rel="noreferrer">NLPM audit findings: 2 recipe bugs + 2 security improvements</a> — was filed on 2026-04-25 and remains open.</p><p>Four PRs were opened (referenced as #757–#760 in the re-audit record) covering the two recipe bugs and the two security findings. All four are CLA-blocked. Google&#39;s public repositories require commit authors to have a signed Contributor License Agreement on file. The default commit identity used by the NLPM contribute pipeline — <code>claude[bot] &lt;claude[bot]@users.noreply.github.com&gt;</code> — is not covered by any CLA. The PRs are technically open but cannot be merged until a human CLA signatory authors the commits — like packages cleared for delivery but waiting on a signature that hasn&#39;t arrived. No pull request URLs are listed in the evidence record for this engagement; this is consistent with the CLA-blocked state documented in the pipeline&#39;s policy gates.</p><p>The flag-inconsistency findings (CC-1) and the quality-only issues were not submitted as PRs. Standard contribute policy reserves PR slots for bugs and security findings only.</p><hr><h2 id="the-response" tabindex="-1">The Response <a class="header-anchor" href="#the-response" aria-label="Permalink to &quot;The Response&quot;">​</a></h2><p>No maintainer comments appear in the evidence record. Issue #761 remains open with no replies as of the re-audit date (2026-05-01). The CLA barrier likely explains the silence: the four associated PRs are stuck before any maintainer would normally engage. One possible explanation is that the issue may read as noise without visible, mergeable PRs to anchor it — but the maintainer may equally have read it and disagreed with the findings, or simply not seen it.</p><p>Based on available pipeline evidence, no commits touching the NL artifacts or security scripts were observed for this engagement; however, individual commit histories and PR states were not directly verified.</p><p>It is also worth noting that <code>googleworkspace/cli</code> is an active, Google-maintained project with a large contributor base. The absence of maintainer engagement on this issue does not indicate quality indifference — the project may have its own conventions for skill descriptions that differ from NLPM&#39;s rubric, and a maintainer reviewing the findings would likely treat some as convention mismatches rather than defects.</p><hr><h2 id="the-re-audit" tabindex="-1">The Re-Audit <a class="header-anchor" href="#the-re-audit" aria-label="Permalink to &quot;The Re-Audit&quot;">​</a></h2><p>A rubric update is a claim; the re-audit verifies the claim against the target repo&#39;s current HEAD.</p><p><strong>Before</strong>: commit <code>a3768d0</code> — score 99/100, 16 findings <strong>After</strong>: commit <code>a3768d0</code> — score 89/100, 121 findings</p><p>The commit SHA is identical. No code changed between the original audit and the re-audit. The re-audit ran at the same HEAD. The scorer had returned to the same building, at the same hour, and come home with a different floor plan.</p><h3 id="per-finding-outcome-table" tabindex="-1">Per-Finding Outcome Table <a class="header-anchor" href="#per-finding-outcome-table" aria-label="Permalink to &quot;Per-Finding Outcome Table&quot;">​</a></h3><blockquote><p><strong>Note:</strong> &quot;Not reproduced (same commit)&quot; means the re-audit scorer did not detect the finding when run at commit <code>a3768d0</code> — not that any code was patched. For CLA-blocked PRs (#757–#760) where no commit changed, the original defect may still be present.</p></blockquote><table tabindex="0"><thead><tr><th>#</th><th>File</th><th>Rule</th><th>Pattern</th><th>Outcome</th><th>PR</th></tr></thead><tbody><tr><td>1</td><td><code>skills/recipe-post-mortem-setup/SKILL.md</code></td><td>BUG-broken-reference</td><td><code>wrong-cli-flags</code></td><td>not reproduced (same commit)</td><td>#757</td></tr><tr><td>2</td><td><code>skills/recipe-collect-form-responses/SKILL.md</code></td><td>BUG-broken-reference</td><td><code>nonexistent-api-method</code></td><td>not reproduced (same commit)</td><td>#758</td></tr><tr><td>3</td><td><code>scripts/show-art.sh</code></td><td>SEC-path-traversal</td><td><code>unvalidated-file-arg</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>4</td><td><code>scripts/coverage.sh</code></td><td>SEC-runtime-package-install</td><td><code>runtime-package-install</code></td><td>not reproduced (same commit)</td><td>#759</td></tr><tr><td>5</td><td><code>package.json</code></td><td>SEC-unpinned-semver</td><td><code>unpinned-semver</code></td><td>not reproduced (same commit)</td><td>#760</td></tr><tr><td>6</td><td><code>skills/recipe-create-shared-drive/SKILL.md</code></td><td>R30</td><td><code>vague-quantifier</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>7</td><td><code>skills/gws-modelarmor/SKILL.md</code></td><td>R05</td><td><code>missing-required-section</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>8</td><td><code>skills/recipe-compare-sheet-tabs/SKILL.md</code></td><td>R22</td><td><code>vague-step-no-command</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>9</td><td><code>skills/recipe-draft-email-from-doc/SKILL.md</code></td><td>R22</td><td><code>vague-step-no-command</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>10</td><td><code>skills/recipe-create-events-from-sheet/SKILL.md</code></td><td>R22</td><td><code>incomplete-loop-step</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>11</td><td><code>skills/recipe-review-overdue-tasks/SKILL.md</code></td><td>R22</td><td><code>vague-step-no-command</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>12</td><td><code>skills/recipe-find-large-files/SKILL.md</code></td><td>R22</td><td><code>vague-step-no-command</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>13</td><td><code>skills/recipe-save-email-to-doc/SKILL.md</code></td><td>R17</td><td><code>flag-inconsistency</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>14</td><td><code>skills/recipe-generate-report-from-sheet/SKILL.md</code></td><td>R17</td><td><code>flag-inconsistency</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>15</td><td><code>skills/recipe-create-doc-from-template/SKILL.md</code></td><td>R17</td><td><code>flag-inconsistency</code></td><td>not reproduced (same commit)</td><td></td></tr><tr><td>16</td><td><code>skills/gws-docs-write/SKILL.md</code></td><td>CC-terminology-drift</td><td><code>flag-name-drift</code></td><td>not reproduced (same commit)</td><td></td></tr></tbody></table><p>Every single original finding resolves as &quot;not reproduced (same commit).&quot; No finding persists into the re-audit. The CLA-blocked PRs were not merged. The commit is unchanged. There is no upstream fix to attribute — &quot;not reproduced&quot; is the pipeline enum label, not confirmation that defects were patched. In other words: nothing moved, but the inventory came out different.</p><h3 id="introduced-findings" tabindex="-1">Introduced Findings <a class="header-anchor" href="#introduced-findings" aria-label="Permalink to &quot;Introduced Findings&quot;">​</a></h3><p>The re-audit introduced 121 findings — eight times the original 16 — none attributable to code changes. Because the commit SHA is identical, these cannot be true regressions from maintainer commits. Two explanations must be named. A third characterization is also appropriate: this is a false-positive inflation event. A tool that produces 8× as many findings on a second run at the same state has a precision problem, not merely a calibration one — like two doctors reading the same X-ray and returning lists that share barely a third of their concerns. 121 of 137 total findings across both runs are unverifiable as real issues — they exist only in one run or the other, not both.</p><p><strong>Scoring drift</strong>: the original audit and the re-audit were run by the same model family (Sonnet 4.6), but model updates between audit and re-audit may have shifted penalty thresholds for criteria like generic descriptions (R03) and missing scope notes (R08). Up to 94 <code>no_scope_note</code> findings and 19 <code>generic_description</code> findings across skill files were all absent from the original run. The <code>no_scope_note</code> findings reflect NLPM&#39;s R08 convention; <code>googleworkspace/cli</code> may not have designed its skill files to conform to this standard.</p><p><strong>Rubric sensitivity shift</strong>: the original scorer may have applied lenient judgment to scope notes and description richness for a 96-artifact library with many 100-scoring files. The re-audit scorer applied stricter thresholds uniformly. Neither run was demonstrably &quot;correct&quot; — both applied the rubric faithfully, with different calibration.</p><p>The most dramatic introduced finding is CLAUDE.md: scored 100 in the original audit, scored 65 in the re-audit. The file is a two-line file whose sole content is a single directive pointing to <code>AGENTS.md</code> — like a receptionist who only says &quot;ask the person down the hall.&quot; Delegating context to <code>AGENTS.md</code> is a legitimate architectural choice — a deliberate single-source-of-truth pattern — and this finding is better characterized as a convention mismatch than a bug. NLPM&#39;s rubric penalizes sparse CLAUDE.md files; a team that has adopted <code>AGENTS.md</code> as their primary agent instruction file would reasonably disagree. This is either a finding the original scorer correctly dismissed, a rubric criterion sharpened between runs, or a combination.</p><h3 id="what-the-diff-proved" tabindex="-1">What the Diff Proved <a class="header-anchor" href="#what-the-diff-proved" aria-label="Permalink to &quot;What the Diff Proved&quot;">​</a></h3><p><strong>16 of 16 original findings not reproduced; 0 still detected.</strong> Since no code changed, &quot;not reproduced&quot; means the re-audit scorer reached a different answer on the same state — not that anyone removed the defects. The re-audit measured identical artifacts and produced different results.</p><hr><h2 id="what-the-audit-revealed" tabindex="-1">What the Audit Revealed <a class="header-anchor" href="#what-the-audit-revealed" aria-label="Permalink to &quot;What the Audit Revealed&quot;">​</a></h2><h3 id="the-cla-barrier-is-structural" tabindex="-1">The CLA Barrier Is Structural <a class="header-anchor" href="#the-cla-barrier-is-structural" aria-label="Permalink to &quot;The CLA Barrier Is Structural&quot;">​</a></h3><p>The googleworkspace/cli engagement confirms what the pipeline&#39;s policy gates were designed to anticipate. Google&#39;s CLA requirement is a hard wall for bot-authored commits. The issue can be filed, the PRs can be opened, but no merge path exists until a human CLA signatory takes ownership. This is not a failure of the audit; it is a documentation of a process limit. The findings were valid. The delivery mechanism hit a known constraint.</p><h3 id="high-quality-skill-libraries-still-have-mechanical-bugs" tabindex="-1">High-Quality Skill Libraries Still Have Mechanical Bugs <a class="header-anchor" href="#high-quality-skill-libraries-still-have-mechanical-bugs" aria-label="Permalink to &quot;High-Quality Skill Libraries Still Have Mechanical Bugs&quot;">​</a></h3><p>A 99/100 score did not prevent two recipes from shipping broken CLI commands — one calling flags that don&#39;t exist, one calling an API method that doesn&#39;t exist. 2 of 96 artifacts (2%) contained functional bugs despite the high aggregate score. Both would fail at runtime with a CLI error, with no warning from the skill text itself. These are the hardest bugs to catch in skill files: the tooling is correct, the prose is clear, and the commands are wrong — a beautifully typeset recipe calling for an ingredient that doesn&#39;t exist. Automated documentation review of CLI flag names against API documentation is exactly the role NLPM is designed to fill.</p><h3 id="maintainer-context" tabindex="-1">Maintainer Context <a class="header-anchor" href="#maintainer-context" aria-label="Permalink to &quot;Maintainer Context&quot;">​</a></h3><p><code>googleworkspace/cli</code> is an active, Google-maintained project. The terse descriptions and minimal CLAUDE.md that NLPM penalizes may reflect deliberate conventions for internal API-wrapper tooling rather than oversights. A namespace-organized skill library where each file covers a named API surface (Gmail, Drive, Calendar) can reasonably argue that the skill name itself supplies the trigger condition, making explicit scope notes redundant. This case study describes NLPM&#39;s rubric applied to that library — a lens, not a verdict. Where findings conflict with what a reasonable maintainer would consider a convention, this article notes it.</p><h3 id="score-volatility-is-real-at-the-high-end" tabindex="-1">Score Volatility Is Real at the High End <a class="header-anchor" href="#score-volatility-is-real-at-the-high-end" aria-label="Permalink to &quot;Score Volatility Is Real at the High End&quot;">​</a></h3><p>A drop from 99 to 89 with no code change is a significant calibration signal — less a verdict than a weather report taken from two thermometers pointed at the same sky. At the low end of the scoring range, a 10-point swing might not change a conclusion. At the high end, where a project is near-perfect by every functional measure, the swing is almost entirely attributable to rubric sensitivity rather than artifact quality. This engagement provides a concrete data point: the same artifacts, the same commit, scored 10 points apart on two different runs. Projects near 100 should treat their scores as a range, not a point estimate.</p><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2>',44)),(i(),r(s,null,{default:t(()=>[d(a,{id:"mermaid-586",class:"mermaid-diagram",graph:"gantt%0A%20%20%20%20title%20googleworkspace%2Fcli%20Engagement%20Timeline%0A%20%20%20%20dateFormat%20YYYY-MM-DD%0A%20%20%20%20axisFormat%20%25m-%25d%0A%0A%20%20%20%20section%20Audit%0A%20%20%20%20NL%20%2B%20security%20audit%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-04-06%2C%201d%0A%0A%20%20%20%20section%20Contribute%0A%20%20%20%20Issue%20%23761%20opened%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-04-25%2C%201d%0A%20%20%20%20PRs%20%23757-760%20(CLA-blocked)%20%20%3Aactive%2C%202026-04-25%2C%207d%0A%0A%20%20%20%20section%20Verify%0A%20%20%20%20Re-audit%20at%20HEAD%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%202026-05-01%2C%201d%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[n(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><p><strong>The re-audit was run at the same commit as the original audit.</strong> The &quot;not reproduced (same commit)&quot; outcome for all 16 findings does not mean the defects were corrected. It means the re-audit scorer did not reproduce the original findings. The diff table shows detection outcomes, not code changes.</p></li><li><p><strong>No maintainer engagement was observed.</strong> The absence of evidence is not evidence that the findings were dismissed. The CLA-blocked PRs may have prevented maintainer visibility.</p></li><li><p><strong>The re-audit measures file-level quality at one point in time; it does not verify that maintainer intent aligns with our rule set.</strong> A maintainer may consider single-phrase descriptions adequate for their use case, or scope notes unnecessary for internal tooling. NLPM&#39;s rubric reflects one set of conventions, not a universal standard.</p></li><li><p><strong>Score comparisons across runs are approximate.</strong> A 10-point drop with no code change demonstrates that the score is a soft measurement, not a deterministic computation. The rubric is applied by a language model whose calibration shifts between deployments.</p></li><li><p><strong>The CLA analysis is based on general policy knowledge confirmed by the pipeline&#39;s own gate logs.</strong> Individual PR states (#757–#760) were not directly inspected.</p></li></ul><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>The googleworkspace/cli engagement matters for two reasons that point in opposite directions.</p><p>The original audit found real bugs in a 99/100 library. That is the intended outcome: high-quality projects still contain mechanical defects, and automated documentation review can surface them faster than manual review. The two recipe bugs — wrong flags, nonexistent API method — would have failed at runtime with a CLI error, with no warning from the skill text itself.</p><p>The re-audit found that score stability is an open problem. Sixteen findings, identified with confidence in April, were not reproducible in May at the same commit. This does not mean the findings were wrong. It means the rubric-as-applied-by-model has variance that the rubric-as-written does not capture. For projects near 100, this variance is the dominant signal. Consumers of NLPM scores at the high end should understand they are reading a probability distribution, not a measurement.</p><p>The score volatility is a tool limitation that consumers should account for. The first result shows what automated NL auditing can find when the signal is clear. The second shows a precision problem: 121 findings introduced at the same commit, 0 of which can be attributed to code changes, means the tool&#39;s false-positive rate at the high end of the scoring range is not yet well-controlled. Both observations are necessary for anyone deciding whether to act on NLPM scores. The most useful thing an imperfect instrument can do is be transparent about the shape of its own imprecision — and that, at least, this engagement managed.</p>',9))])}const A=c(u,[["render",p]]);export{k as __pageData,A as default};
